let totalMinutes = 0;
let meetings = [];
let busyBlocks = [];

const UAE_OFFSET = 4; // UTC+4

function toUAE(dateString) {
  const date = new Date(dateString);
  date.setHours(date.getUTCHours() + UAE_OFFSET);
  return date;
}

function formatTime(date) {
  return date.toLocaleTimeString("en-AE", {
    hour: "2-digit",
    minute: "2-digit",
    hour12: true
  });
}

const now = new Date();
const todayStart = new Date(now);
todayStart.setHours(8 - UAE_OFFSET, 0, 0, 0);

const todayEnd = new Date(now);
todayEnd.setHours(18 - UAE_OFFSET, 0, 0, 0);

for (const item of items) {

  const startRaw = item.json.start?.dateTime || item.json.start?.date;
  const endRaw = item.json.end?.dateTime || item.json.end?.date;

  if (!startRaw || !endRaw) continue;

  const start = toUAE(startRaw);
  const end = toUAE(endRaw);

  if (isNaN(start) || isNaN(end)) continue;

  const duration = (end - start) / 60000;
  totalMinutes += duration;

  meetings.push({ start, end });
  busyBlocks.push([start, end]);
}

busyBlocks.sort((a, b) => a[0] - b[0]);

let freeWindows = [];
let cursor = todayStart;

for (const block of busyBlocks) {
  if (block[0] > cursor) {
    freeWindows.push(
      `${formatTime(cursor)} - ${formatTime(block[0])}`
    );
  }
  cursor = block[1] > cursor ? block[1] : cursor;
}

if (cursor < todayEnd) {
  freeWindows.push(
    `${formatTime(cursor)} - ${formatTime(todayEnd)}`
  );
}

if (meetings.length === 0) {
  freeWindows = ["08:00 AM - 06:00 PM"];
}

return [{
  json: {
    totalHours: (totalMinutes / 60).toFixed(1),
    meetingCount: meetings.length,
    freeWindows,
    overloaded: meetings.length > 4
  }
}];

